async function callClaude(env, systemPrompt, messages, streaming = false, maxTokens = 1024) {
  const MAX_RETRIES = 2;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "x-api-key": env.ANTHROPIC_API_KEY,
          "anthropic-version": "2023-06-01",
          "content-type": "application/json",
          "anthropic-beta": "prompt-caching-2024-07-31"
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: maxTokens,
          stream: false,
          system: [{ type: "text", text: systemPrompt, cache_control: { type: "ephemeral" } }],
          messages
        })
      });
      if (!res.ok) {
        if ([429, 500, 502, 503, 529].includes(res.status) && attempt < MAX_RETRIES) {
          await new Promise((r) => setTimeout(r, (attempt + 1) * 3e3));
          continue;
        }
        console.error(`[callClaude] API error: ${res.status}`);
        return "";
      }
      const data = await res.json();
      return data.content?.[0]?.text || "";
    } catch (err) {
      if (attempt < MAX_RETRIES) {
        await new Promise((r) => setTimeout(r, (attempt + 1) * 3e3));
        continue;
      }
      console.error("[callClaude] Failed after retries:", err.message);
      return "";
    }
  }
  return "";
}
