async function checkHeuristicFlags(env, sessionId, session, phaseNumber) {
  const messages = session.messages || [];
  const userMessages = messages.filter(function(m) {
    return m.role === "user";
  });
  const flags = [];
  if (userMessages.length >= 3) {
    const recentUserMsgs = userMessages.slice(-3);
    const avgWords = recentUserMsgs.reduce(function(sum, m) {
      return sum + (m.content || "").split(/\s+/).length;
    }, 0) / recentUserMsgs.length;
    if (avgWords < 40) {
      flags.push({ type: "red", message: "Low engagement: avg " + Math.round(avgWords) + " words per response (last 3 messages)" });
    }
  }
  if (session.blueprintGenerated && messages.length < 15) {
    flags.push({ type: "red", message: "Rushed interview: only " + messages.length + " total messages before blueprint" });
  }
  const fullTranscript = userMessages.map(function(m) {
    return m.content || "";
  }).join(" ");
  const namedPersonPattern = /\b[A-Z][a-z]+ [A-Z][a-z]+\b|\b(my (?:wife|husband|partner|mentor|boss|father|mother|friend|colleague))\b/i;
  if (userMessages.length >= 8 && !namedPersonPattern.test(fullTranscript)) {
    flags.push({ type: "yellow", message: "Abstract storytelling: no named individuals mentioned" });
  }
  const uncertaintyPattern = /i don'?t know|not sure|i'?m not sure|unsure|can'?t say/gi;
  const phaseUserMessages = userMessages.slice(-6);
  const uncertaintyCount = phaseUserMessages.filter(function(m) {
    return uncertaintyPattern.test(m.content || "");
  }).length;
  if (uncertaintyCount >= 2) {
    flags.push({ type: "red", message: "Uncertainty/disengagement in Phase " + phaseNumber + ": " + uncertaintyCount + " uncertain responses" });
  }
  if (userMessages.length >= 6) {
    const lengths = userMessages.map(function(m) {
      return (m.content || "").split(/\s+/).length;
    });
    const avg = lengths.reduce(function(a, b) {
      return a + b;
    }, 0) / lengths.length;
    const variance = lengths.reduce(function(sum, l) {
      return sum + Math.pow(l - avg, 2);
    }, 0) / lengths.length;
    if (variance < 100 && userMessages.length >= 8) {
      flags.push({ type: "yellow", message: "Flat emotional trajectory: consistent response length, no emotional arc detected" });
    }
  }
  if (flags.length > 0) {
    const redFlags = flags.filter(function(f) {
      return f.type === "red";
    }).map(function(f) {
      return f.message;
    });
    const yellowFlags = flags.filter(function(f) {
      return f.type === "yellow";
    }).map(function(f) {
      return f.message;
    });
    await env.DB.prepare(
      `UPDATE phase_scores SET red_flags = ?, yellow_flags = ? WHERE session_id = ? AND phase = ?`
    ).bind(
      JSON.stringify(redFlags),
      JSON.stringify(yellowFlags),
      sessionId,
      phaseNumber
    ).run().catch(function() {
      env.DB.prepare(
        `INSERT INTO phase_scores (id, session_id, phase, engagement, red_flags, yellow_flags, phase_summary)
         VALUES (?, ?, ?, 'heuristic', ?, ?, 'Heuristic flags only')`
      ).bind(
        "ps_h_" + sessionId + "_" + phaseNumber + "_" + Date.now(),
        sessionId,
        phaseNumber,
        JSON.stringify(redFlags),
        JSON.stringify(yellowFlags)
      ).run().catch(function() {
      });
    });
  }
  return flags;
}
