async function logApiCost(env, { sessionId, userEmail, model, callType, usage }) {
  try {
    if (!usage || !sessionId)
      return 0;
    const rate = API_RATES[model] || API_RATES["claude-sonnet-4-6"];
    const inputTokens = usage.input_tokens || 0;
    const outputTokens = usage.output_tokens || 0;
    const cost = inputTokens * rate.input / 1e6 + outputTokens * rate.output / 1e6;
    await env.DB.prepare(
      `INSERT INTO api_costs (id, session_id, user_email, api_provider, model, call_type, input_tokens, output_tokens, cost_usd)
       VALUES (?, ?, ?, 'anthropic', ?, ?, ?, ?, ?)`
    ).bind(
      "ac_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
      sessionId,
      userEmail || null,
      model,
      callType,
      inputTokens,
      outputTokens,
      cost
    ).run();
    return cost;
  } catch (err) {
    console.error("[CostLog] Failed:", err.message);
    return 0;
  }
}
