async function handleAuthLogin(request, env) {
  try {
    const { email, password } = await request.json();
    if (!email || !password)
      return json({ error: "Both email and password are required. We need both. Like peanut butter and jelly." }, 400);
    const ip4 = request.headers.get("CF-Connecting-IP") || "unknown";
    if (await authRateLimit(env, (email || "unknown") + ":" + ip4))
      return json({ error: "You have attempted to sign in so many times we are starting to feel concerned. Please wait 15 minutes." }, 429);
    const user = await getUserByEmail(env, email);
    if (!user)
      return json({ error: "We have never seen that email before. Double check the address, or use the Magic Link option to get in without a password." }, 401);
    if (!user.password_hash)
      return json({ error: `This account does not have a password set. Click "Magic Link" and we will email you a sign-in link. No password required.` }, 401);
    const valid = await verifyPassword(password, user.password_hash);
    if (!valid) {
      await trackFunnelEvent(env, "login_failed", { email, reason: "wrong_password" });
      return json({ error: "That password is not right. Give it another shot, or use the Magic Link option to skip the whole password thing." }, 401);
    }
    await updateLastLogin(env, user.id);
    const secret = getJWTSecret(env);
    const token = await createSessionToken(user.id, user.role, secret);
    await trackFunnelEvent(env, "login_success", { userId: user.id, method: "password" });
    return json({
      token,
      user: { id: user.id, email: user.email, name: user.name, role: user.role, tier: user.tier }
    });
  } catch (e) {
    await logError(env, { endpoint: "/api/auth/login", method: "POST", statusCode: 500, errorType: "auth_error", errorMessage: e.message, stack: e.stack });
    return json({ error: "Something went wrong signing you in. Please try again in a moment." }, 500);
  }
}
