    const body = await request.json();
    const { sessionId } = body;
    if (!sessionId)
      return json({ error: "sessionId required" }, 400);
    const row = await env.DB.prepare(`SELECT user_id FROM sessions WHERE id = ?`).bind(sessionId).first();
