async function handleAdminWeeklySnapshots(request, env) {
  const admin = await requireAdmin(request, env);
  if (!admin)
    return json({ error: "Forbidden" }, 403);
  try {
    const url = new URL(request.url);
    const weeks = parseInt(url.searchParams.get("weeks") || "12");
    const limit = Math.min(weeks, 52);
    const rows = await env.DB.prepare(
      `SELECT id, week_start, week_end, snapshot_data, created_at
       FROM weekly_snapshots
       ORDER BY week_start DESC
       LIMIT ?`
    ).bind(limit).all();
    const snapshots = (rows?.results || []).map(function(r) {
      var data;
      try {
        data = JSON.parse(r.snapshot_data);
      } catch (_) {
        data = null;
      }
      return {
        id: r.id,
        week_start: r.week_start,
        week_end: r.week_end,
        data,
        created_at: r.created_at
      };
    });
    return json({ snapshots, count: snapshots.length });
  } catch (e) {
    return json({ error: e.message }, 500);
  }
}
