async function handleAdminCreateWeeklySnapshot(request, env) {
  const admin = await requireAdmin(request, env);
  if (!admin)
    return json({ error: "Forbidden" }, 403);
  try {
    const body = await request.json();
    const { week_start, week_end, snapshot_data } = body;
    if (!week_start || !week_end || !snapshot_data) {
      return json({ error: "week_start, week_end, and snapshot_data are required" }, 400);
    }
    if (!/^\d{4}-\d{2}-\d{2}$/.test(week_start) || !/^\d{4}-\d{2}-\d{2}$/.test(week_end)) {
      return json({ error: "Dates must be in YYYY-MM-DD format" }, 400);
    }
    const id = "ws_" + week_start.replace(/-/g, "") + "_" + Date.now();
    const dataStr = typeof snapshot_data === "string" ? snapshot_data : JSON.stringify(snapshot_data);
    await env.DB.prepare(
      `INSERT INTO weekly_snapshots (id, week_start, week_end, snapshot_data)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(id) DO UPDATE SET snapshot_data = excluded.snapshot_data, created_at = datetime('now')`
    ).bind(id, week_start, week_end, dataStr).run().catch(async function() {
      await env.DB.prepare("DELETE FROM weekly_snapshots WHERE week_start = ?").bind(week_start).run().catch(function() {
      });
      await env.DB.prepare(
        "INSERT INTO weekly_snapshots (id, week_start, week_end, snapshot_data) VALUES (?, ?, ?, ?)"
      ).bind(id, week_start, week_end, dataStr).run();
    });
    return json({ ok: true, id, week_start, week_end });
  } catch (e) {
    return json({ error: e.message }, 500);
  }
}
